Bind a relay command to a Dropdown's selection change using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SelectionCommandBinder _selectionCommand;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Selection(int index) { }
    }


Bind a relay command to a Dropdown in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Dropdown _dropdown;
        
        private SelectionCommandBinder SelectionCommand => new(_dropdown);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Selection(int index) { }
    }

